/// Validate that a resolved CLI command can be executed.
///
/// Checks if the executable exists as a path or in the system PATH.
/// Returns a clear error if the executable cannot be found, allowing
/// early failure before attempting to spawn the process.
pub(crate) fn validate_cli_executable(resolved_cli: &str) -> Result<()> {
    let path = Path::new(resolved_cli);

    // If it's an absolute or relative path, check if the file exists
    if path.is_absolute() || resolved_cli.contains(std::path::MAIN_SEPARATOR) {
        if path.exists() {
            return Ok(());
        }
        return Err(anyhow!(
            "executable not found: '{}' does not exist",
            resolved_cli
        ));
    }

    // For bare commands, search in PATH
    if let Ok(path_env) = std::env::var("PATH") {
        for dir in std::env::split_paths(&path_env) {
            let candidate = dir.join(resolved_cli);
            if candidate.exists() {
                return Ok(());
            }
        }
    }

    Err(anyhow!(
        "executable not found: '{}' is not in PATH or does not exist",
        resolved_cli
    ))
}
